```mermaid
xychart-beta
    title "Annual Sales by Region (in $ millions)"
    x-axis "Year" {
        type category
        categories ["Year 1", "Year 2"]
    }
    y-axis "Sales ($M)" {
        min 0
        max 200
    }
    bar "North" {
        data [120, 150]
    }
    bar "South" {
        data [90, 100]
    }
    bar "West" {
        data [70, 85]
    }
```

```mermaid
xychart-beta
    title "Project Completion Rates Over Time"
    x-axis "Month" {
        type category
        categories ["Jan", "Feb", "Mar", "Apr", "May"]
    }
    y-axis "Completion Rate (%)" {
        min 0
        max 100
    }
    line "Project A" {
        data [20, 35, 50, 65, 80]
    }
    line "Project B" {
        data [10, 25, 45, 70, 90]
    }
```

```mermaid
xychart-beta
    title "Employee Distribution by Department and Gender"
    x-axis "Department" {
        type category
        categories ["Sales", "Marketing", "R&D"]
    }
    y-axis "Number of Employees" {
        min 0
        max 100
    }
    bar "Male" {
        data [40, 25, 30]
    }
    bar "Female" {
        data [30, 35, 20]
    }
```

```mermaid
xychart-beta
    title "Quarterly Sales Performance (in $ thousands)"
    x-axis "Quarter" {
        type category
        categories ["Q1", "Q2", "Q3", "Q4"]
    }
    y-axis "Sales ($K)" {
        min 0
        max 100
    }
    bar "Product X" {
        data [60, 75, 80, 95]
    }
    bar "Product Y" {
        data [40, 50, 65, 70]
    }
```

```mermaid
xychart-beta
    title "Quarterly Sales by Region (in thousands of USD)"
    x-axis "Quarter" {
        type category
        categories ["Q1", "Q2", "Q3", "Q4"]
    }
    y-axis "Sales (000 USD)" {
        type linear
        min 0
        max 200
    }
    bar "Region A" {
        data [120, 130, 140, 150]
    }
    bar "Region B" {
        data [150, 160, 170, 180]
    }
    bar "Region C" {
        data [100, 110, 120, 130]
    }
```

```mermaid
xychart-beta
    title "Stock Prices of Company X and Company Y (USD)"
    x-axis "Month" {
        type category
        categories ["Jan", "Feb", "Mar", "Apr", "May", "Jun"]
    }
    y-axis "Price (USD)" {
        type linear
        min 40
        max 100
    }
    line "Company X" {
        data [50, 60, 75, 70, 85, 90]
    }
    line "Company Y" {
        data [80, 70, 65, 75, 80, 70]
    }
```

```mermaid
xychart-beta
    title "Market Share Distribution by Company (Percentage)"
    x-axis "Year" {
        type category
        categories ["2018", "2019", "2020", "2021"]
    }
    y-axis "Market Share (%)" {
        type linear
        min 0
        max 100
    }
    bar "Company P" {
        data [30, 25, 20, 15]
        stacked true
    }
    bar "Company Q" {
        data [20, 25, 30, 35]
        stacked true
    }
    bar "Company R" {
        data [40, 35, 30, 25]
        stacked true
    }
    bar "Others" {
        data [10, 15, 20, 25]
        stacked true
    }
```

```mermaid
xychart-beta
    title "Advertising Spend vs. Sales Revenue (in thousands of USD)"
    x-axis "Advertising Spend (000 USD)" {
        type linear
        min 0
        max 100
    }
    y-axis "Sales Revenue (000 USD)" {
        type linear
        min 0
        max 150
    }
    scatter "Data Points" {
        data [[10, 20], [20, 35], [30, 50], [40, 60], [50, 75], [60, 90], [70, 100], [80, 110], [90, 125], [25, 80]]
    }
```
